import pytest
import requests

BASE_URL = "http://localhost:8080/fhir"

@pytest.fixture
def auth_headers():
    return <fixture_authorized_bulk_client_headers>

def test_bulk_export_authorized_client_queues_job(auth_headers):
    resp = requests.get(
        f"{BASE_URL}/$export",
        headers={
            **auth_headers,
            "Accept": "application/fhir+json",
            "Prefer": "respond-async",
        },
    )
    assert resp.status_code == 202, f"Expected 202, got {resp.status_code}"
    assert "Content-Location" in resp.headers, "Missing Content-Location header"
    poll_url = resp.headers["Content-Location"]
    assert poll_url.startswith("http"), f"Unexpected poll URL: {poll_url}"

import pytest
import requests

BASE_URL = "http://localhost:8080/fhir"
EPOCH_BOUNDARY = "1970-01-01T00:00:00Z"

@pytest.fixture
def auth_headers():
    return <fixture_authorized_bulk_client_headers>

def test_bulk_export_since_epoch_boundary_timestamp(auth_headers):
    resp = requests.get(
        f"{BASE_URL}/$export",
        params={"_since": EPOCH_BOUNDARY},
        headers={
            **auth_headers,
            "Accept": "application/fhir+json",
            "Prefer": "respond-async",
        },
    )
    assert resp.status_code == 202, f"Expected 202 for epoch _since, got {resp.status_code}"
    assert "Content-Location" in resp.headers, "Missing Content-Location on epoch boundary request"
